class Solution:
    def removeOccurrences(self, s, part):
        stack = []
        m = len(part)
        for ch in s:
            stack.append(ch)
            if len(stack) >= m and ''.join(stack[-m:]) == part:
                del stack[-m:]
        return ''.join(stack)

