var removeOccurrences = function(s, part) {
    const stack = [];
    const m = part.length;
    for (const ch of s) {
        stack.push(ch);
        if (stack.length >= m && stack.slice(stack.length - m).join('') === part) {
            stack.length -= m;
        }
    }
    return stack.join('');
};
